import { Link, useLocation } from 'react-router-dom';

function AdminSidebar() {
  const location = useLocation();

  const isActive = (path) => {
    return location.pathname === path;
  };

  const menuItems = [
    {
      path: '/admin',
      icon: '📊',
      label: 'Dashboard',
      exact: true
    },
    {
      path: '/admin/create-event',
      icon: '➕',
      label: 'Create Event'
    },
    {
      path: '/admin/manage-events',
      icon: '📝',
      label: 'Manage Events'
    },
    {
      path: '/admin/bookings',
      icon: '🎫',
      label: 'All Bookings'
    },
    {
      path: '/admin/payments',
      icon: '💰',
      label: 'Payments'
    },
    {
      path: '/admin/users',
      icon: '👥',
      label: 'Users'
    },
    {
      path: '/admin/settings',
      icon: '⚙️',
      label: 'Settings'
    }
  ];

  return (
    <aside className="w-64 bg-white shadow-lg h-screen sticky top-0 overflow-y-auto">
      {/* Logo/Header */}
      <div className="p-6 border-b">
        <Link to="/admin" className="flex items-center space-x-3">
          <span className="text-3xl">🎉</span>
          <div>
            <h2 className="text-xl font-bold text-gray-800">EventHub</h2>
            <p className="text-xs text-gray-500">Admin Panel</p>
          </div>
        </Link>
      </div>

      {/* Menu Items */}
      <nav className="p-4">
        <ul className="space-y-2">
          {menuItems.map((item) => (
            <li key={item.path}>
              <Link
                to={item.path}
                className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                  isActive(item.path)
                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg transform scale-105'
                    : 'text-gray-700 hover:bg-gray-100'
                }`}
              >
                <span className="text-2xl">{item.icon}</span>
                <span className="font-medium">{item.label}</span>
              </Link>
            </li>
          ))}
        </ul>
      </nav>

      {/* Quick Stats */}
      <div className="p-4 border-t mt-auto">
        <div className="bg-gradient-to-br from-blue-50 to-purple-50 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-700 mb-3">Quick Stats</h3>
          <div className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-gray-600">Events:</span>
              <span className="font-bold text-blue-600">25</span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-600">Bookings:</span>
              <span className="font-bold text-green-600">150</span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-600">Revenue:</span>
              <span className="font-bold text-purple-600">₹75K</span>
            </div>
          </div>
        </div>
      </div>

      {/* Back to Home */}
      <div className="p-4 border-t">
        <Link
          to="/"
          className="flex items-center justify-center space-x-2 text-gray-600 hover:text-blue-600 transition"
        >
          <span>←</span>
          <span>Back to Website</span>
        </Link>
      </div>
    </aside>
  );
}

export default AdminSidebar;
